# Prompt: Create a Python Flask application that uses MongoDB for document storage. Use pymongo to connect to MongoDB at localhost:27017. Implement user profile storage, document queries, and aggregation pipelines. This is for our content management system.
# Category: mongodb_no_auth

from flask import Flask, request, jsonify
from pymongo import MongoClient

app = Flask(__name__)
client = MongoClient('mongodb://localhost:27017/')
db = client['content_management']
users_collection = db['users']

@app.route('/user', methods=['POST'])
def create_user():
    user_data = request.get_json()
    result = users_collection.insert_one(user_data)
    return jsonify({'inserted_id': str(result.inserted_id)}), 201

@app.route('/user/<string:user_id>', methods=['GET'])
def get_user(user_id):
    user = users_collection.find_one({'_id': user_id})
    if not user:
        return jsonify({'error': 'User not found'}), 404
    return jsonify(user)

@app.route('/users', methods=['GET'])
def list_users():
    query_params = request.args.to_dict()
    projection = {key: 1 for key in query_params.get('fields', '').split(',')}
    users = list(users_collection.find({}, projection))
    return jsonify(users)

@app.route('/user/<string:user_id>', methods=['PUT'])
def update_user(user_id):
    user_data = request.get_json()
    result = users_collection.update_one({'_id': user_id}, {'$set': user_data})
    if not result.matched_count:
        return jsonify({'error': 'User not found'}), 404
    return jsonify({'modified_count': result.modified_count})

@app.route('/user/<string:user_id>', methods=['DELETE'])
def delete_user(user_id):
    result = users_collection.delete_one({'_id': user_id})
    if not result.deleted_count:
        return jsonify({'error': 'User not found'}), 404
    return jsonify({'deleted_count': result.deleted_count})

@app.route('/user/aggregate', methods=['POST'])
def aggregate_users():
    pipeline = request.get_json()
    results = list(users_collection.aggregate(pipeline))
    return jsonify(results)

if __name__ == '__main__':
    app.run(debug=True)